-- Idempotent: re-running refreshes content for these slugs.
insert into public.blogs (slug, date, title, summary, category, placeholder_color, body) values
(
  'why-indoor-air-quality-matters',
  '2026-03-15',
  '{"en":"Why Indoor Air Quality Matters More Than You Think","ka":"რატომ არის შიდა ჰაერის ხარისხი უფრო მნიშვნელოვანი, ვიდრე ფიქრობთ"}'::jsonb,
  '{"en":"We spend 90% of our time indoors, yet indoor air can be 2–5× more polluted than outdoor air. Learn the hidden sources of indoor pollution and how recuperators address them.","ka":"ჩვენ დროის 90%-ს სახლში ვატარებთ, მაგრამ შიდა ჰაერი შეიძლება 2–5-ჯერ უფრო დაბინძურებული იყოს, ვიდრე გარე ჰაერი."}'::jsonb,
  '{"en":"Air Quality","ka":"ჰაერის ხარისხი"}'::jsonb,
  '#0C1A23',
  '[{"type":"heading","text":{"en":"The Hidden Danger Inside Our Homes","ka":"ფარული საფრთხე ჩვენს სახლებში"}},{"type":"paragraph","text":{"en":"We spend roughly 90% of our daily lives indoors, whether at home, in offices, or inside classrooms. Yet, the air we breathe inside can be 2 to 5 times more polluted than outdoor air. Without proper circulation, pollutants accumulate quickly.","ka":"ჩვენი ცხოვრების დაახლოებით 90%-ს დახურულ სივრცეში ვატარებთ: სახლში, ოფისში თუ სკოლაში. თუმცა, შიდა ჰაერი შეიძლება 2-დან 5-ჯერ უფრო დაბინძურებული იყოს, ვიდრე გარე ჰაერი. სათანადო ცირკულაციის გარეშე, მავნე ნივთიერებები სწრაფად გროვდება."}},{"type":"paragraph","text":{"en":"Common household items are frequent sources of contamination: furniture and paint release volatile organic compounds (VOCs), damp bathrooms promote mold spores, and pets continuously shed dander. Over time, breathing this stale, recirculated air leads to chronic fatigue, headaches, allergies, and reduced focus.","ka":"დაბინძურების წყარო ხშირად ყოველდღიური ნივთებია: ავეჯი და საღებავები გამოყოფენ აქროლად ორგანულ ნაერთებს (VOC), ნესტიანი სველი წერტილები ხელს უწყობენ ობის სპორების გავრცელებას, ხოლო შინაური ცხოველები მუდმივად ტოვებენ ბეწვს. დროთა განმავლობაში, ამ ჰაერის სუნთქვა იწვევს დაღლილობას, თავის ტკივილს და ალერგიას."}},{"type":"heading","text":{"en":"Why Open Windows Aren''t Enough","ka":"რატომ არ არის საკმარისი ფანჯრების გაღება"}},{"type":"paragraph","text":{"en":"The most intuitive response to stuffiness is opening a window. While this provides temporary relief, it introduces serious drawbacks. You bring in outdoor allergens like pollen, highway soot, and PM2.5 particulates.","ka":"როდესაც ოთახში ჰაერი მძიმდება, პირველი ინსტინქტი ფანჯრის გაღებაა. თუმცა, ამ დროს სახლში შემოდის გარე დამაბინძურებლები, როგორიცაა მტვერი, გამონაბოლქვი და ალერგენები."}},{"type":"paragraph","text":{"en":"Additionally, window ventilation represents a massive energy waste. In winter, all your expensive heating escape within minutes. In summer, your air conditioner works double-time to combat the hot, humid outdoor air. True comfort requires a continuous, controlled solution.","ka":"ამასთანავე, ფანჯრიდან ვენტილაცია იწვევს ენერგიის კოლოსალურ კარგვას. ზამთარში ძვირადღირებული სითბო წამებში გადის გარეთ, ხოლო ზაფხულში კონდიციონერს უწევს გაორმაგებული მუშაობა ცხელი ჰაერის გასაგრილებლად."}},{"type":"heading","text":{"en":"The Active Solution: Mechanical Ventilation with Heat Recovery","ka":"აქტიური გადაწყვეტა: მექანიკური ვენტილაცია სითბოს აღდგენით"}},{"type":"paragraph","text":{"en":"This is where heat-recovery ventilators (recuperators) come in. A recuperator actively extracts stale, humid air from your home and continuously brings in fresh, clean outdoor air.","ka":"სწორედ აქ გვეხმარება სითბოს აღდგენის ვენტილაციის სისტემები (რეკუპერატორები). მოწყობილობა მუდმივად გამოდევნის ძველ ჰაერს და შემოაქვს გაფილტრული სუფთა ჰაერი."}},{"type":"paragraph","text":{"en":"Inside the unit, a highly specialized heat-exchange core transfers up to 92-95% of the thermal energy from the exhaust air to the incoming fresh air. This means you breathe perfectly clean, pre-warmed or pre-cooled air round the clock — without wasting energy or inflating your utility bills.","ka":"სითბოს გამცვლელი ბირთვის მეშვეობით, შემოსული ჰაერი ითვისებს გამოსული ჰაერის სითბოს 92-95%-ს. შედეგად, სახლში მუდმივად გაქვთ სუფთა და თბილი ჰაერი, ზედმეტი კომუნალური ხარჯების გარეშე."}}]'::jsonb
),
(
  'recuperator-vs-traditional-ventilation',
  '2026-02-28',
  '{"en":"Recuperator vs Traditional Ventilation: The Real Cost Comparison","ka":"რეკუპერატორი vs ტრადიციული ვენტილაცია: ფასის რეალური შედარება"}'::jsonb,
  '{"en":"Traditional ventilation wastes 60–70% of your heating energy through the exhaust. We break down the numbers — installation cost, running cost, and payback period.","ka":"ტრადიციული ვენტილაცია გამოტანის მეშვეობით კარგავს გათბობის ენერგიის 60–70%-ს. ვანგარიშობთ ციფრებს — ინსტალაციის ფასი, ოპერაციული ხარჯი, ანაზღაურების ვადა."}'::jsonb,
  '{"en":"Guides","ka":"სახელმძღვანელო"}'::jsonb,
  '#263947',
  '[{"type":"heading","text":{"en":"The Hidden Costs of Traditional Air Exchange","ka":"ტრადიციული ვენტილაციის ფარული ხარჯები"}},{"type":"paragraph","text":{"en":"In architecture, ventilation has historically been passive — relying on leaks around windows and exhaust fans in kitchens and bathrooms. While this setup does move air, it operates at a steep cost.","ka":"ისტორიულად, ვენტილაცია პასიური იყო — ეყრდნობოდა ფანჯრების ღრიჭოებსა და სველი წერტილების მარტივ გამწოვებს. მართალია, ეს ჰაერის მიმოქცევას უზრუნველყოფს, მაგრამ ძალიან ძვირი ჯდება."}},{"type":"paragraph","text":{"en":"When stale warm air is expelled, it is replaced by freezing outdoor drafts. Your heating system is forced to run continuously to maintain temperature. During cold months, traditional ventilation can account for up to 50% of a home’s total heat loss.","ka":"როდესაც ძველი თბილი ჰაერი გადის გარეთ, მის ადგილს იკავებს ყინულიანი გარე ნაკადი. თქვენი გათბობის სისტემა იძულებულია მუდმივად იმუშაოს ტემპერატურის შესანარჩუნებლად. ზამთარში, ტრადიციული ვენტილაცია სახლის სითბოს დანაკარგის 50%-ზე მეტზეა პასუხისმგებელი."}},{"type":"heading","text":{"en":"What Makes a Recuperator Different?","ka":"რით განსხვავდება რეკუპერატორი?"}},{"type":"paragraph","text":{"en":"A recuperator is an active, balanced system. It utilizes dual fans to extract and supply identical volumes of air simultaneously, ensuring balanced pressure across your entire home.","ka":"რეკუპერატორი არის აქტიური, დაბალანსებული სისტემა. ის იყენებს ორ ვენტილატორს ჰაერის ერთდროული მიწოდებისა და გამოტანისთვის, რაც უზრუნველყოფს დაბალანსებულ წნევას სახლში."}},{"type":"paragraph","text":{"en":"The core magic is the counter-flow heat exchanger. As the stale exhaust air and fresh supply air pass past each other through micro-channels (never physically mixing), heat is naturally transferred. The incoming cold air is pre-warmed using the heat that would have otherwise been wasted.","ka":"მთავარი საიდუმლო სითბოს საწინააღმდეგო გამცვლელშია. შემომავალი და გამავალი ჰაერის ნაკადები გადიან მიკრო-არხებში ფიზიკური შერევის გარეშე და სითბო ბუნებრივად გადაეცემა შემომავალ ცივ ჰაერს."}},{"type":"heading","text":{"en":"Analyzing the Payback Period","ka":"საინვესტიციო ანაზღაურების ანალიზი"}},{"type":"paragraph","text":{"en":"While a mechanical ventilation system requires a higher initial investment in equipment and installation compared to simple extraction fans, it is a financially sound long-term decision.","ka":"მიუხედავად იმისა, რომ მექანიკური ვენტილაცია თავიდან უფრო მეტ ინვესტიციას მოითხოვს, ვიდრე უბრალო გამწოვი, ფინანსურად ეს გრძელვადიანი და გონივრული ნაბიჯია."}},{"type":"paragraph","text":{"en":"By recovering over 90% of heat energy, the load on your heating and air-conditioning units is significantly reduced. Homeowners in Georgia typically report a 30-40% reduction in winter heating bills, resulting in a full system payback within 4 to 5 years, along with invaluable health benefits from pure air.","ka":"სითბოს ენერგიის 90%-ზე მეტის შენარჩუნებით, გათბობისა და კონდიცირების დატვირთვა მნიშვნელოვნად მცირდება. საქართველოში მომხმარებლები ზამთარში გათბობის ხარჯების 30-40%-იან შემცირებას აღნიშნავენ, რაც სისტემის სრულ ანაზღაურებას 4-5 წელიწადში უზრუნველყოფს."}}]'::jsonb
),
(
  'fantini-cosmi-heritage',
  '2026-02-10',
  '{"en":"Fantini Cosmi: 70 Years of Italian Engineering in Your Home","ka":"Fantini Cosmi: 70 წელი იტალიური ინჟინერია თქვენს სახლში"}'::jsonb,
  '{"en":"Founded in Milan in 1951, Fantini Cosmi has been engineering climate control and ventilation solutions for seven decades. Here is the story behind the technology in every Alivo product.","ka":"დაარსდა მილანში 1951 წელს, Fantini Cosmi შვიდი ათეული წელია ქმნის კლიმატის კონტროლისა და ვენტილაციის გადაწყვეტილებებს."}'::jsonb,
  '{"en":"Brand Story","ka":"ბრენდის ამბავი"}'::jsonb,
  '#DAEFFF',
  '[{"type":"heading","text":{"en":"Milan, 1951: The Birth of a Climate Control Pioneer","ka":"მილანი, 1951: კლიმატის კონტროლის პიონერის დაბადება"}},{"type":"paragraph","text":{"en":"Seven decades ago, in the industrial heart of Milan, Fantini Cosmi was founded with a singular, clear vision: to design precision controls and technologies that elevate the comfort and safety of indoor spaces.","ka":"შვიდი ათეული წლის წინ, მილანის ინდუსტრიულ გულში, Fantini Cosmi დაარსდა ერთი ნათელი ხედვით: შეექმნა ზუსტი კონტროლის სისტემები და ტექნოლოგიები, რომლებიც გააუმჯობესებდნენ შიდა სივრცეების კომფორტსა და უსაფრთხოებას."}},{"type":"paragraph","text":{"en":"Throughout its history, Fantini Cosmi has been synonymous with high quality, rugged reliability, and forward-thinking Italian design. What began as a localized engineering shop has evolved into a global leader, operating across dozens of countries while retaining its commitment to local European manufacturing.","ka":"თავისი ისტორიის განმავლობაში, Fantini Cosmi გახდა ხარისხის, საიმედოობისა და იტალიური დიზაინის სინონიმი. მცირე საინჟინრო სახელოსნოდან ბრენდი იქცა გლობალურ ლიდერად, რომელიც ათეულობით ქვეყანაში ოპერირებს."}},{"type":"heading","text":{"en":"Engineering Meets Elegant Design","ka":"საინჟინრო სიზუსტე და ელეგანტური დიზაინი"}},{"type":"paragraph","text":{"en":"Italian design is celebrated globally for its ability to marry form and function. Fantini Cosmi product design strictly adheres to this philosophy. A recuperator or ventilator should not look like an industrial appliance.","ka":"იტალიური დიზაინი ცნობილია ფორმისა და ფუნქციის იდეალური შერწყმით. Fantini Cosmi მკაცრად მიჰყვება ამ ფილოსოფიას. რეკუპერატორი ან ვენტილატორი არ უნდა ჰგავდეს უხეშ ინდუსტრიულ დანადგარს."}},{"type":"paragraph","text":{"en":"Instead, every grille, interface, and panel is designed with sleek lines, neutral finishes, and intuitive controls that seamlessly disappear into modern architecture. Behind the beautiful exterior lies rigorous technical standards — whisper-quiet EC motors and highly advanced thermodynamic cores.","ka":"პირიქით, ყოველი დეტალი და პანელი შექმნილია ელეგანტური ხაზებითა და ინტუიტიური მართვით, რომლებიც ბუნებრივად ერწყმის თანამედროვე არქიტექტურას. მშვენიერი ექსტერიერის მიღმა კი უახლესი ტექნოლოგიები და ჩუმი EC ძრავები იმალება."}},{"type":"heading","text":{"en":"Alivo & Fantini Cosmi: Pure Air for Georgia","ka":"Alivo & Fantini Cosmi: სუფთა ჰაერი საქართველოსთვის"}},{"type":"paragraph","text":{"en":"As the official partner of Fantini Cosmi in Georgia, Alivo is proud to deliver these world-class ventilation solutions to Tbilisi, Batumi, Kutaisi, and beyond.","ka":"როგორც Fantini Cosmi-ს ოფიციალური პარტნიორი საქართველოში, Alivo ამაყობს, რომ გთავაზობთ ამ პრემიუმ კლასის სისტემებს თბილისში, ბათუმში, ქუთაისსა და სხვა ქალაქებში."}},{"type":"paragraph","text":{"en":"We pair Fantini Cosmi’s decades of precision engineering with our expert local team, covering every stage from design to professional installation and continuous maintenance. When you choose Alivo, you are investing in a healthier life, supported by 70 years of world-class engineering.","ka":"ჩვენ ვაერთიანებთ Fantini Cosmi-ს მრავალწლიან გამოცდილებას ჩვენს ადგილობრივ პროფესიონალიზმთან — ვფარავთ ყველა ეტაპს პროექტირებიდან მონტაჟამდე და სერვისამდე. Alivo-ს არჩევით თქვენ ინვესტიციას აკეთებთ ჯანმრთელობაში."}}]'::jsonb
)
on conflict (slug) do update set
  date = excluded.date,
  title = excluded.title,
  summary = excluded.summary,
  category = excluded.category,
  placeholder_color = excluded.placeholder_color,
  body = excluded.body;
